    for (query in queries) {
        val l = query[0].toInt()
        val r = query[1].toInt()
        val k = query[2].toInt()

        // 1. Identify the set of removed even numbers from nums[l..r]
        val removedEvens = mutableSetOf<Long>()
        for (i in l..r) {
            val num = nums[i]
            if (num % 2 == 0L) {
                removedEvens.add(num)
            }
        }

        // 2. The sequence of all positive even numbers is 2, 4, 6, 8, ...
        // The nth positive even number is 2*n.

        // 3. We are looking for the k-th smallest positive even number that is NOT in removedEvens.
        // Let the target number be T = 2 * m. We are looking for the smallest m such that
        // the count of even numbers <= T minus the count of removed evens <= T is at least k.

        // Count of even numbers <= T is floor(T / 2) = m.
        // Let removedCount(T) be the count of numbers in removedEvens that are <= T.
        // We need to find the smallest T = 2m such that:
        // m - removedCount(2m) >= k

        // Since removedEvens is a set of specific even numbers, we can pre-calculate a function
        // to find removedCount(T) efficiently.

        // Sort the removed evens to easily count those <= T
        val sortedRemovedEvens = removedEvens.toMutableList().apply { sort() }

        // Binary search for m (or T=2m).
        // The maximum possible value for T needs to be estimated.
        // The k-th smallest number is at least 2k.
        // The largest number in nums is 10^9. The maximum number we might check could be around 2*k + |removedEvens|.
        // Since k <= 10^9 and |removedEvens| <= 10^5, T is roughly 2*10^9.

        var lowM = 1L // Smallest possible m (T=2)
        // A safe upper bound for m. If k=10^9 and no evens are removed, m=10^9.
        // If all numbers up to 2*10^9 are removed, we might need more, but k is the target rank.
        // Max T we might need to check is roughly 2 * (k + |removedEvens|)
        var highM = 2_000_000_000L + 100000L // Safe upper bound for m

        var ansM = highM

        while (lowM <= highM) {
            val midM = lowM + (highM - lowM) / 2
            val T = midM * 2

            // Count how many removed evens are <= T
            // This is equivalent to finding the count of elements in sortedRemovedEvens <= T
            var removedCount = 0
            var idx = 0
            while (idx < sortedRemovedEvens.size && sortedRemovedEvens[idx] <= T) {
                removedCount++
                idx++
            }

            // Number of remaining evens <= T is midM - removedCount
            val remainingCount = midM - removedCount

            if (remainingCount >= k) {
                // T (or midM) might be the answer, try for a smaller one
                ansM = midM
                highM = midM - 1
            } else {
                // Not enough remaining evens, need a larger T
                lowM = midM + 1
            }
        }

        // The result is 2 * ansM
        results.add(ansM * 2L)
    }

    return results.toTypedArray()
}
